import { useNavigate } from "react-router-dom";
import { useState } from "react";

export default function CreateHome() {
  const navigate = useNavigate();

  const [homeName, setHomeName] = useState("");
  const [guestCount, setGuestCount] = useState("");
  const [adminType, setAdminType] = useState("");
  const [error, setError] = useState("");

  const handleCreate = () => {
    if (!homeName.trim() || !guestCount || !adminType) {
      setError("please complete all fields");
      return;
    }

    setError("");

    navigate("/home-ready", {
      state: {
        type: "create",
        homeName,
        guestCount,
        adminType,
      },
    });
  };

  const sharedInputStyle =
    "w-full h-[72px] rounded-[14px] bg-[#f3eeee] px-5 text-[1.1rem] text-[#7b5a4d] outline-none border-none shadow-none focus:outline-none focus:ring-0 focus:border-none";

  return (
    <main className="min-h-screen bg-[#eadbc9] flex items-center justify-center px-6">
      <section className="w-full max-w-[1200px] flex flex-col items-center text-center -mt-10">
        <h1
          className="text-[#6b4b3e] mb-10"
          style={{
            fontSize: "clamp(3.2rem, 5.2vw, 5rem)",
            lineHeight: 1,
            fontFamily: '"Trebuchet MS", "Segoe UI", sans-serif',
            fontWeight: 600,
          }}
        >
          create your home
        </h1>

        <div className="w-full max-w-[560px] text-left">
          <label
            className="block text-[#6b4b3e] mb-2"
            style={{
              fontSize: "2rem",
              fontFamily: '"Trebuchet MS", "Segoe UI", sans-serif',
            }}
          >
            name your home:
          </label>

          <input
            type="text"
            value={homeName}
            onChange={(e) => setHomeName(e.target.value)}
            placeholder="type here.."
            className={`${sharedInputStyle} mb-8 placeholder:text-[#b9aeaa] text-[1.25rem]`}
            style={{ fontFamily: '"Trebuchet MS", "Segoe UI", sans-serif' }}
          />

          <div className="relative mb-8">
            <select
              value={guestCount}
              onChange={(e) => setGuestCount(e.target.value)}
              className={`${sharedInputStyle} appearance-none pr-14 ${
                guestCount ? "text-[#7b5a4d]" : "text-[#7b5a4d]"
              }`}
              style={{
                fontFamily: '"Trebuchet MS", "Segoe UI", sans-serif',
                WebkitAppearance: "none",
                MozAppearance: "none",
              }}
            >
              <option value="" disabled hidden>
                select amount of guests
              </option>
              <option value="">select amount of guests</option>
              <option value="2">2 guests</option>
              <option value="3">3 guests</option>
              <option value="4">4 guests</option>
              <option value="5">5 guests</option>
              <option value="6">6 guests</option>
            </select>

            <span
              className="absolute right-5 top-1/2 -translate-y-1/2 pointer-events-none"
              style={{
                color: "#9a7262",
                fontSize: "1.7rem",
                lineHeight: 1,
              }}
            >
              ▶
            </span>
          </div>

          <div className="relative">
            <select
              value={adminType}
              onChange={(e) => setAdminType(e.target.value)}
              className={`${sharedInputStyle} appearance-none pr-14`}
              style={{
                fontFamily: '"Trebuchet MS", "Segoe UI", sans-serif',
                WebkitAppearance: "none",
                MozAppearance: "none",
              }}
            >
              <option value="" disabled hidden>
                select admin type
              </option>
              <option value="">select admin type</option>
              <option value="home owner">home owner</option>
              <option value="house hold member">house hold member</option>
              <option value="admin">admin</option>
            </select>

            <span
              className="absolute right-5 top-1/2 -translate-y-1/2 pointer-events-none"
              style={{
                color: "#9a7262",
                fontSize: "1.7rem",
                lineHeight: 1,
              }}
            >
              ▶
            </span>
          </div>
        </div>

        {error ? (
          <p
            className="mt-5 mb-2 text-[#8b4b45]"
            style={{
              fontSize: "1.05rem",
              fontFamily: '"Trebuchet MS", "Segoe UI", sans-serif',
            }}
          >
            {error}
          </p>
        ) : null}

        <button
          onClick={handleCreate}
          className="mt-12 w-[250px] h-[68px] rounded-[18px] bg-[#aab095] text-[#43332c] hover:brightness-[0.98] active:translate-y-[1px] transition border border-[rgba(90,62,54,0.22)]"
          style={{
            fontFamily: '"Trebuchet MS", "Segoe UI", sans-serif',
            fontSize: "2rem",
            lineHeight: 1,
          }}
        >
          create
        </button>
      </section>
    </main>
  );
}
